+            .map_err(|e| CliError::Other(format!("{context} live sqlite snapshot failed: {e}")))?;
+        Ok(Self {
+            actual_path,
+            reported_path,
+            kind: CanonicalSnapshotSourceKind::LiveSnapshot,
+            _snapshot_dir: Some(snapshot_dir),
+        })
