+
+    fn actual_path(&self) -> &Path {
+        &self.actual_path
+    }
+
+    fn reported_path(&self) -> &Path {
+        &self.reported_path
+    }
+
+    fn uses_archive_snapshot(&self) -> bool {
+        matches!(self.kind, CanonicalSnapshotSourceKind::ArchiveSnapshot)
+    }
